import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import shiftService from '../../services/shiftService';
import employeeService from '../../services/employeeService';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import Badge from '../../components/common/Badge';
import Modal from '../../components/common/Modal';
import Input, { Select } from '../../components/common/Input';
import Spinner from '../../components/common/Spinner';
import Alert from '../../components/common/Alert';
import './ShiftsPage.css';

const DAYS = ['Lun', 'Mar', 'Mie', 'Joi', 'Vin', 'Sâm', 'Dum'];

const emptyForm = {
  name: '', startTime: '09:00', endTime: '17:00',
  daysOfWeek: [1, 2, 3, 4, 5], breakMinutes: 30, color: '#1e3a5f', isActive: true,
};

export default function ShiftsPage() {
  const { isAdminOrManager } = useAuth();
  const [shifts, setShifts] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [formError, setFormError] = useState('');

  const [assignModal, setAssignModal] = useState(false);
  const [assignShift, setAssignShift] = useState(null);
  const [assignEmployee, setAssignEmployee] = useState('');
  const [assigning, setAssigning] = useState(false);

  const fetchShifts = useCallback(async () => {
    setLoading(true);
    try {
      const res = await shiftService.getAll();
      setShifts(res.data?.data || res.data || []);
    } catch {
      setError('Eroare la încărcarea turelor.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchShifts();
    employeeService.getAll({ limit: 200 }).then(r => {
      setEmployees(r.data?.data || r.data || []);
    }).catch(() => {});
  }, [fetchShifts]);

  const openCreate = () => {
    setEditTarget(null);
    setForm(emptyForm);
    setFormError('');
    setShowModal(true);
  };

  const openEdit = (shift) => {
    setEditTarget(shift);
    setForm({
      name: shift.name || '',
      startTime: shift.startTime || '09:00',
      endTime: shift.endTime || '17:00',
      daysOfWeek: shift.daysOfWeek || [1, 2, 3, 4, 5],
      breakMinutes: shift.breakMinutes ?? 30,
      color: shift.color || '#1e3a5f',
      isActive: shift.isActive !== false,
    });
    setFormError('');
    setShowModal(true);
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const toggleDay = (day) => {
    setForm(prev => ({
      ...prev,
      daysOfWeek: prev.daysOfWeek.includes(day)
        ? prev.daysOfWeek.filter(d => d !== day)
        : [...prev.daysOfWeek, day].sort(),
    }));
  };

  const handleSave = async () => {
    if (!form.name || !form.startTime || !form.endTime) {
      return setFormError('Numele, ora de început și de sfârșit sunt obligatorii.');
    }
    setSaving(true);
    setFormError('');
    try {
      if (editTarget) {
        await shiftService.update(editTarget.id, form);
      } else {
        await shiftService.create(form);
      }
      setShowModal(false);
      fetchShifts();
    } catch (err) {
      setFormError(err.response?.data?.message || 'Eroare la salvare.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (shift) => {
    if (!window.confirm(`Ștergi tura "${shift.name}"?`)) return;
    try {
      await shiftService.delete(shift.id);
      fetchShifts();
    } catch (err) {
      alert(err.response?.data?.message || 'Eroare la ștergere.');
    }
  };

  const openAssign = (shift) => {
    setAssignShift(shift);
    setAssignEmployee('');
    setAssignModal(true);
  };

  const handleAssign = async () => {
    if (!assignEmployee) return;
    setAssigning(true);
    try {
      await shiftService.assign(assignShift.id, assignEmployee);
      setAssignModal(false);
      fetchShifts();
    } catch (err) {
      alert(err.response?.data?.message || 'Eroare la asignare.');
    } finally {
      setAssigning(false);
    }
  };

  const empOptions = [
    { value: '', label: '— Selectează angajat —' },
    ...employees.map(e => ({ value: e.id, label: `${e.firstName} ${e.lastName}` })),
  ];

  return (
    <div className="shifts-page">
      <div className="shifts-header">
        <div>
          <h1>Ture</h1>
          <p className="text-muted">{shifts.length} tur{shifts.length !== 1 ? 'e' : 'ă'} configurate</p>
        </div>
        {isAdminOrManager && (
          <Button variant="primary" onClick={openCreate}>+ Tură nouă</Button>
        )}
      </div>

      {loading ? (
        <div className="shifts-loading"><Spinner /></div>
      ) : error ? (
        <Alert type="danger">{error}</Alert>
      ) : shifts.length === 0 ? (
        <Card><Card.Body className="text-center text-muted p-2">Nicio tură configurată.</Card.Body></Card>
      ) : (
        <div className="shifts-grid">
          {shifts.map(shift => (
            <Card key={shift.id} className="shift-card">
              <Card.Body>
                <div className="shift-card-header">
                  <div className="shift-color-dot" style={{ background: shift.color }} />
                  <h3 className="shift-name">{shift.name}</h3>
                  <Badge color={shift.isActive ? 'success' : 'default'}>
                    {shift.isActive ? 'Activ' : 'Inactiv'}
                  </Badge>
                </div>

                <div className="shift-info">
                  <div className="shift-info-row">
                    <span>🕐 Ore</span>
                    <strong>{shift.startTime} – {shift.endTime}</strong>
                  </div>
                  <div className="shift-info-row">
                    <span>☕ Pauză</span>
                    <strong>{shift.breakMinutes} min</strong>
                  </div>
                  <div className="shift-info-row">
                    <span>👥 Angajați</span>
                    <strong>{shift.Users?.length ?? 0}</strong>
                  </div>
                </div>

                <div className="shift-days">
                  {DAYS.map((label, idx) => (
                    <span
                      key={idx}
                      className={`day-pill ${(shift.daysOfWeek || []).includes(idx + 1) ? 'active' : ''}`}
                    >
                      {label}
                    </span>
                  ))}
                </div>

                {isAdminOrManager && (
                  <div className="shift-actions">
                    <Button variant="ghost" size="sm" onClick={() => openAssign(shift)}>Asignează</Button>
                    <Button variant="ghost" size="sm" onClick={() => openEdit(shift)}>Editează</Button>
                    <Button variant="danger" size="sm" onClick={() => handleDelete(shift)}>Șterge</Button>
                  </div>
                )}
              </Card.Body>
            </Card>
          ))}
        </div>
      )}

      {/* Create / Edit Modal */}
      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={editTarget ? 'Editează tură' : 'Tură nouă'}
        size="md"
        footer={
          <>
            <Button variant="secondary" onClick={() => setShowModal(false)}>Anulează</Button>
            <Button variant="primary" loading={saving} onClick={handleSave}>Salvează</Button>
          </>
        }
      >
        {formError && <Alert type="danger" className="mb-4">{formError}</Alert>}
        <div className="shift-form">
          <Input label="Nume tură *" name="name" value={form.name} onChange={handleChange} />
          <div className="shift-form-row">
            <Input label="Ora început *" name="startTime" type="time" value={form.startTime} onChange={handleChange} />
            <Input label="Ora sfârșit *" name="endTime" type="time" value={form.endTime} onChange={handleChange} />
          </div>
          <Input label="Pauză (minute)" name="breakMinutes" type="number" value={form.breakMinutes} onChange={handleChange} />
          <div className="form-group">
            <label className="input-label">Zile lucrătoare</label>
            <div className="days-picker">
              {DAYS.map((label, idx) => (
                <button
                  key={idx}
                  type="button"
                  className={`day-btn ${form.daysOfWeek.includes(idx + 1) ? 'selected' : ''}`}
                  onClick={() => toggleDay(idx + 1)}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>
          <div className="shift-form-row">
            <div className="form-group">
              <label className="input-label">Culoare</label>
              <input type="color" name="color" value={form.color} onChange={handleChange} className="color-picker" />
            </div>
            <div className="form-group">
              <label className="input-label">Status</label>
              <label className="toggle-label">
                <input type="checkbox" name="isActive" checked={form.isActive} onChange={handleChange} />
                <span>{form.isActive ? 'Activ' : 'Inactiv'}</span>
              </label>
            </div>
          </div>
        </div>
      </Modal>

      {/* Assign Modal */}
      <Modal
        isOpen={assignModal}
        onClose={() => setAssignModal(false)}
        title={`Asignează angajat la: ${assignShift?.name}`}
        size="sm"
        footer={
          <>
            <Button variant="secondary" onClick={() => setAssignModal(false)}>Anulează</Button>
            <Button variant="primary" loading={assigning} onClick={handleAssign} disabled={!assignEmployee}>Asignează</Button>
          </>
        }
      >
        <Select
          label="Selectează angajat"
          value={assignEmployee}
          onChange={e => setAssignEmployee(e.target.value)}
          options={empOptions}
        />
      </Modal>
    </div>
  );
}
